Create 17 API route files in the citedby-ai project at C:\Users\User\citedby-ai. Each route is a Next.js App Router API route (POST handler).

IMPORTANT: Each route should:
1. Import the service function(s)
2. Export a POST handler that reads JSON body, calls the service, returns JSON response
3. Handle errors with try/catch returning 500 status

Here are the routes to create:

### 1. app/api/ai/generate/route.ts
```typescript
import { NextRequest, NextResponse } from 'next/server';
import { generateSolution, generateBlogArchitecture, generateFullArticle } from '@/services/generator';

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { action, ...params } = body;

    let result;
    switch (action) {
      case 'solution':
        result = await generateSolution(params.recommendation, params.url);
        break;
      case 'blogArchitecture':
        result = await generateBlogArchitecture(params.topic, params.url);
        break;
      case 'fullArticle':
        result = await generateFullArticle(params.briefContent, params.topic);
        break;
      default:
        return NextResponse.json({ error: 'Unknown action' }, { status: 400 });
    }
    return NextResponse.json({ result });
  } catch (error: any) {
    return NextResponse.json({ error: error.message || 'Internal error' }, { status: 500 });
  }
}
```

